import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const parseParams = (value) => {
    if (!value) {
        return {};
    }
    return Object.fromEntries(new URLSearchParams(value));
};

export default function AuthCallback() {
    const navigate = useNavigate();
    const [error, setError] = useState('');

    useEffect(() => {
        let active = true;

        const run = async () => {
            const hashParams = parseParams(window.location.hash.replace(/^#/, ''));
            const queryParams = parseParams(window.location.search.replace(/^\?/, ''));
            const accessToken = hashParams.access_token || queryParams.access_token || '';
            const refreshToken = hashParams.refresh_token || queryParams.refresh_token || '';
            const oauthError = hashParams.error_description || queryParams.error_description || '';

            if (!accessToken) {
                if (active) {
                    setError(oauthError || 'Social signup failed. Please try again.');
                }
                return;
            }

            localStorage.setItem('auth_token', accessToken);
            if (refreshToken) {
                localStorage.setItem('refresh_token', refreshToken);
            }

            try {
                navigate('/dashboard', { replace: true });
            } catch {
                navigate('/dashboard', { replace: true });
            }
        };

        run();

        return () => {
            active = false;
        };
    }, [navigate]);

    return (
        <div className="auth-page">
            <div className="auth-container">
                <div className="auth-modal">
                    <div className="auth-modal__body" style={{ textAlign: 'center' }}>
                        {error ? (
                            <div className="alert alert-danger">{error}</div>
                        ) : (
                            <p>Completing social signup...</p>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}
